import React, {useEffect, useMemo, useState} from 'react';
import {createRoot} from 'react-dom/client';
import {FiBell, FiCalendar, FiCheck, FiChevronDown, FiChevronLeft, FiChevronRight, FiClock, FiDownload, FiEye, FiFilter, FiHelpCircle, FiHome, FiLock, FiMail, FiMapPin, FiMenu, FiMinusCircle, FiMoreHorizontal, FiPhone, FiPlus, FiRefreshCw, FiSearch, FiSettings, FiUpload, FiUser} from 'react-icons/fi';
import {GiCarrot, GiCorn, GiFarmTractor, GiFertilizerBag, GiGrain, GiPlantRoots, GiPotato, GiTomato, GiWheat, GiSprout} from 'react-icons/gi';
import {FaBoxesStacked, FaCartShopping, FaChartLine, FaClipboardCheck, FaLeaf, FaRegUser, FaRubleSign, FaStore, FaUsers} from 'react-icons/fa6';
import {MdInventory2, MdOutlineApi, MdOutlineSell, MdWarningAmber, MdWaterDrop, MdInfoOutline, MdLocalShipping} from 'react-icons/md';
import './style.css';
import './analytics.css';
import './auth.css';

const API = import.meta.env.VITE_API_URL || 'http://localhost:8080';
async function api(path, opts = {}) {
  const r = await fetch(API + path, {headers: {'Content-Type': 'application/json'}, ...opts});
  if (!r.ok) throw new Error(await r.text());
  return r.json();
}
const post = (p, b) => api(p, {method: 'POST', body: JSON.stringify(b)});
const patch = (p, b) => api(p, {method: 'PATCH', body: JSON.stringify(b)});
const del = (p) => api(p, {method: 'DELETE'});
async function uploadFile(path, file) {
  const body = new FormData();
  body.append('file', file);
  const r = await fetch(API + path, {method: 'POST', body});
  if (!r.ok) throw new Error(await r.text());
  return r.json();
}
async function downloadFile(path, fallbackName = 'export.xlsx') {
  const r = await fetch(API + path);
  if (!r.ok) throw new Error(await r.text());
  const blob = await r.blob();
  const disposition = r.headers.get('Content-Disposition') || '';
  const match = disposition.match(/filename=([^;]+)/i);
  const filename = match?.[1]?.replaceAll('"', '') || fallbackName;
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = filename;
  a.click();
  URL.revokeObjectURL(url);
}
const num = (v, fallback = 0) => Number(v ?? fallback);
const formatDate = (value) => value ? new Date(value).toLocaleDateString('ru-RU') : '—';
const formatKg = (value) => `${num(value).toLocaleString('ru-RU')} кг`;
const cropTypeFromName = (name = '') => {
  const v = name.toLowerCase();
  if (v.includes('карто')) return 'potato';
  if (v.includes('томат')) return 'tomato';
  if (v.includes('огур')) return 'cucumber';
  if (v.includes('пшен')) return 'wheat';
  if (v.includes('лук')) return 'onion';
  if (v.includes('куку')) return 'corn';
  if (v.includes('морков')) return 'carrot';
  return 'sprout';
};
const plantingStatusMeta = (status = '') => {
  if (status === 'harvested') return {label: 'Завершен', cls: 'harvested', filter: 'harvested'};
  if (status === 'cancelled') return {label: 'Отменен', cls: 'cancelled', filter: 'cancelled'};
  if (status === 'planned') return {label: 'Планируемый', cls: 'planned', filter: 'planned'};
  return {label: 'Активный', cls: 'active', filter: 'active'};
};
const plantingProgress = (planting) => {
  if (planting.status === 'harvested') return 100;
  if (planting.status === 'planned') return 0;
  const start = planting.planting_date ? new Date(planting.planting_date) : null;
  const end = planting.planned_harvest_date ? new Date(planting.planned_harvest_date) : null;
  if (!start || !end || Number.isNaN(start.getTime()) || Number.isNaN(end.getTime()) || end <= start) return planting.status === 'active' ? 45 : 0;
  const ratio = ((Date.now() - start.getTime()) / (end.getTime() - start.getTime())) * 100;
  return Math.max(0, Math.min(100, Math.round(ratio)));
};
const plantingStageLabel = (progress, status) => {
  if (status === 'harvested') return 'Собрано';
  if (status === 'planned') return 'Планируется';
  if (progress < 25) return 'Посажено';
  if (progress < 60) return 'Растет';
  if (progress < 90) return 'Созревает';
  return 'Готово к сбору';
};
const downloadCSV = (filename, rows) => {
  const csv = rows.map(row => row.map(v => `"${String(v ?? '').replaceAll('"', '""')}"`).join(',')).join('\n');
  const blob = new Blob([csv], {type: 'text/csv;charset=utf-8;'});
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = filename;
  a.click();
  URL.revokeObjectURL(url);
};
const weatherCodeMap = {
  0: ['Ясно', '☀️'], 1: ['Преимущественно ясно', '🌤️'], 2: ['Переменная облачность', '⛅'], 3: ['Пасмурно', '☁️'],
  45: ['Туман', '🌫️'], 48: ['Иней', '🌫️'], 51: ['Лёгкая морось', '🌦️'], 53: ['Морось', '🌦️'], 55: ['Сильная морось', '🌧️'],
  61: ['Небольшой дождь', '🌦️'], 63: ['Дождь', '🌧️'], 65: ['Сильный дождь', '⛈️'], 71: ['Небольшой снег', '🌨️'],
  80: ['Ливень', '🌧️'], 81: ['Сильный ливень', '⛈️'], 95: ['Гроза', '⛈️']
};
async function fetchWeatherForFarm(farm) {
  const fallback = {name: 'Грозный', latitude: 43.3178, longitude: 45.6982};
  const query = encodeURIComponent(farm?.address || farm?.region || farm?.name || fallback.name);
  let place = fallback;
  try {
    const geo = await fetch(`https://geocoding-api.open-meteo.com/v1/search?name=${query}&count=1&language=ru&format=json`);
    if (geo.ok) {
      const geoJson = await geo.json();
      const first = geoJson?.results?.[0];
      if (first) place = {name: first.name, latitude: first.latitude, longitude: first.longitude};
    }
  } catch {}
  const forecast = await fetch(`https://api.open-meteo.com/v1/forecast?latitude=${place.latitude}&longitude=${place.longitude}&current=temperature_2m,weather_code,wind_speed_10m,relative_humidity_2m&daily=temperature_2m_max,temperature_2m_min,precipitation_probability_max&timezone=auto&forecast_days=3`);
  if (!forecast.ok) throw new Error('weather');
  const json = await forecast.json();
  const code = json.current?.weather_code ?? 0;
  const [label, icon] = weatherCodeMap[code] || ['Погода обновляется', '🌤️'];
  return {
    location: place.name,
    label,
    icon,
    currentTemp: json.current?.temperature_2m,
    wind: json.current?.wind_speed_10m,
    humidity: json.current?.relative_humidity_2m,
    daily: (json.daily?.time || []).map((day, i) => ({
      day,
      min: json.daily?.temperature_2m_min?.[i],
      max: json.daily?.temperature_2m_max?.[i],
      rain: json.daily?.precipitation_probability_max?.[i]
    })).slice(0, 3)
  };
}

function App() {
  const [session, setSession] = useState(() => localStorage.getItem('agrocrm-session'));
  const [tab, setTab] = useState('dashboard');
  const [data, setData] = useState({});
  const [msg, setMsg] = useState('');
  const [modal, setModal] = useState(null);
  const sessionData = useMemo(() => {
    try { return session ? JSON.parse(session) : null; } catch { return null; }
  }, [session]);
  const activeFarmId = sessionData?.farmId || 1;
  const load = async () => {
    const keys = ['fields', 'crops', 'inventory', 'plantings', 'tasks', 'harvests', 'customers', 'sales'];
    const out = {};
    await Promise.all(keys.map(async k => out[k] = await api(`/farms/${activeFarmId}/${k}`)));
    out.me = await api('/auth/me');
    out.farm = await api(`/farms/${activeFarmId}`);
    out.dashboard = await api(`/farms/${activeFarmId}/dashboard`);
    out.apiKeys = await api(`/farms/${activeFarmId}/api-keys`);
    out.products = await api('/public/products');
    try { out.weather = await fetchWeatherForFarm(out.farm); } catch { out.weather = null; }
    setData(out);
  };
  useEffect(() => { if (sessionData) load().catch(e => setMsg(e.message)); }, [activeFarmId, sessionData]);
  const crop = data.crops?.[0], field = data.fields?.[0], harvestItem = data.inventory?.find(i => i.type === 'harvest'), customer = data.customers?.[0], planting = data.plantings?.[0];
  const me = data.me || sessionData || {};
  const farm = data.farm || {};
  const modalKind = typeof modal === 'string' ? modal : modal?.kind;
  const submitAction = async (kind, form) => {
    if (kind === 'field') await post(`/farms/${activeFarmId}/fields`, {name: form.name, areaHectares: Number(form.areaHectares), location: form.location, soilType: form.soilType, status: form.status});
    if (kind === 'planting') await post(`/farms/${activeFarmId}/plantings`, {fieldID: Number(form.fieldID), cropID: Number(form.cropID), seedQuantityKg: Number(form.seedQuantityKg), expectedYieldKg: Number(form.expectedYieldKg)});
    if (kind === 'inventory') await post(`/farms/${activeFarmId}/inventory`, {type: form.type, name: form.name, cropId: Number(form.cropID || 0), quantityKg: Number(form.quantityKg), minQuantityKg: Number(form.minQuantityKg || 0), averageCostPerKg: Number(form.averageCostPerKg || 0), unit: form.unit || 'кг'});
    if (kind === 'task') await post(`/farms/${activeFarmId}/tasks`, {title: form.title, description: form.description, type: form.type, status: 'todo', dueDate: form.dueDate, fieldID: Number(form.fieldID || 0), plantingID: Number(form.plantingID || 0)});
    if (kind === 'harvest') await post(`/farms/${activeFarmId}/harvests`, {plantingID: Number(form.plantingID || 0), cropID: Number(form.cropID), quantityKg: Number(form.quantityKg), qualityGrade: form.qualityGrade});
    if (kind === 'customer') await post(`/farms/${activeFarmId}/customers`, {name: form.name, phone: form.phone, email: form.email, type: form.type, address: form.address, notes: form.notes});
    if (kind === 'sale') await post(`/farms/${activeFarmId}/sales`, {customerID: Number(form.customerID), inventoryItemID: Number(form.inventoryItemID), quantityKg: Number(form.quantityKg), pricePerKg: Number(form.pricePerKg)});
    setModal(null); setMsg('Данные сохранены'); await load();
  };
  const actions = useMemo(() => ({
    open(kind) { setModal(kind); },
    goTo(nextTab) { setTab(nextTab); },
    async importData(kind) { const input = document.createElement('input'); input.type = 'file'; input.accept = '.xlsx'; input.onchange = async () => { const file = input.files?.[0]; if (!file) return; await uploadFile(`/farms/${activeFarmId}/import/${kind}`, file); setMsg(`Импорт ${kind} завершён`); await load(); }; input.click(); },
    async exportXLSX(kind) { await downloadFile(`/farms/${activeFarmId}/export/${kind}`, `${kind}.xlsx`); setMsg(`Экспорт ${kind} готов`); },
    exportRows(filename, rows) { downloadCSV(filename, rows); },
    async saveProfile(form) { const resp = await patch('/auth/me', {farmId: activeFarmId, ...form}); const current = {...(sessionData || {}), name: form.name || sessionData?.name}; localStorage.setItem('agrocrm-session', JSON.stringify(current)); setSession(JSON.stringify(current)); setMsg('Профиль сохранён'); await load(); return resp; },
    async saveFarm(form) { await patch(`/farms/${activeFarmId}`, form); setMsg('Настройки хозяйства сохранены'); await load(); },
    async updateField(id, form) { await patch(`/fields/${id}`, form); setMsg('Поле обновлено'); await load(); },
    async deleteField(id) { await del(`/fields/${id}`); setMsg('Поле удалено'); await load(); },
    planting() { setModal('planting'); },
    openPlantingEdit(plantingRow) { setModal({kind: 'edit-planting', planting: plantingRow}); },
    async updatePlanting(id, form) { await patch(`/plantings/${id}`, {fieldID: Number(form.fieldID), cropID: Number(form.cropID), seedQuantityKg: Number(form.seedQuantityKg), expectedYieldKg: Number(form.expectedYieldKg || 0), status: form.status, plantingDate: form.plantingDate, plannedHarvestDate: form.plannedHarvestDate}); setMsg('Посев обновлен'); await load(); },
    async deletePlanting(id) { await del(`/plantings/${id}`); setMsg('Посев удален'); await load(); },
    async completePlanting(id) { await post(`/plantings/${id}/complete`, {}); setMsg('Посев завершен'); await load(); },
    async updateInventory(id, form) { await patch(`/inventory/${id}`, form); setMsg('Склад обновлен'); await load(); },
    async deleteInventory(id) { await del(`/inventory/${id}`); setMsg('Позиция склада удалена'); await load(); },
    async adjustInventory(id, deltaKg) { await post(`/inventory/${id}/adjust`, {deltaKg: Number(deltaKg)}); setMsg('Остаток скорректирован'); await load(); },
    async updateTask(id, form) { await patch(`/tasks/${id}`, form); setMsg('Задача обновлена'); await load(); },
    async completeTask(id) { await post(`/tasks/${id}/complete`, {}); setMsg('Задача завершена'); await load(); },
    async deleteTask(id) { await del(`/tasks/${id}`); setMsg('Задача удалена'); await load(); },
    async updateHarvest(id, form) { await patch(`/harvests/${id}`, form); setMsg('Запись урожая обновлена'); await load(); },
    async deleteHarvest(id) { await del(`/harvests/${id}`); setMsg('Запись урожая удалена'); await load(); },
    async updateCustomer(id, form) { await patch(`/customers/${id}`, form); setMsg('Клиент обновлен'); await load(); },
    async deleteCustomer(id) { await del(`/customers/${id}`); setMsg('Клиент удален'); await load(); },
    async updateSale(id, form) { await patch(`/sales/${id}`, form); setMsg('Продажа обновлена'); await load(); },
    async deleteSale(id) { await del(`/sales/${id}`); setMsg('Продажа удалена'); await load(); },
    async createApiKey(name) { const res = await post(`/farms/${activeFarmId}/api-keys`, {name}); setMsg(`API ключ создан: ${res.apiKey}`); await load(); return res; },
    async revokeApiKey(id) { await patch(`/api-keys/${id}/revoke`, {}); setMsg('API ключ отозван'); await load(); },
    harvest() { setModal('harvest'); },
    sale() { setModal('sale'); },
    async order() { await post('/public/orders', {customerName: 'Кафе Беркат', phone: '+7 900 000 00 00', items: [{productId: harvestItem?.id, quantityKg: 300}]}); setMsg('Внешний заказ принят через публичный API'); load(); }
  }), [activeFarmId, field, crop, planting, customer, harvestItem, sessionData]);

  const menu = [
    ['dashboard', 'Главная', FiHome], ['fields', 'Поля', FiMapPin], ['plantings', 'Посевы', GiWheat], ['inventory', 'Склад', FaStore], ['tasks', 'Задачи', FaClipboardCheck], ['harvests', 'Урожай', GiPlantRoots], ['customers', 'Клиенты', FaUsers], ['sales', 'Продажи', MdOutlineSell], ['analytics', 'Аналитика', FaChartLine], ['api', 'API', MdOutlineApi], ['settings', 'Настройки', FiSettings]
  ];

  if (!sessionData) return <AuthPage onLogin={(payload) => { localStorage.setItem('agrocrm-session', JSON.stringify(payload)); setSession(JSON.stringify(payload)); }} />;

  return <div className="shell">
    <aside className="sidebar">
      <div className="brand"><div className="logo"><FaLeaf /></div><span>AgroCRM</span></div>
      <nav>{menu.map(([id, title, Icon]) => <button key={id} className={tab === id ? 'active' : ''} onClick={() => setTab(id)}><Icon />{title}</button>)}</nav>
      <div className="farm-card"><div className="farm-img"><GiFarmTractor /></div><b>{farm.name || 'Ферма Ахмат'}</b><span>{farm.region || 'Чеченская Республика'}</span><em>{farm.address || 'Овощное хозяйство'}</em></div>
      <div className="profile"><div><FaRegUser /></div><p><b>{me.name || 'Ахмат Исаев'}</b><span>{me.role === 'owner' ? 'Владелец фермы' : (me.role || 'Пользователь')}</span></p><FiChevronRight /></div>
    </aside>
    <main className="content">
      <Topbar farm={farm} me={me} onLogout={() => { localStorage.removeItem('agrocrm-session'); setSession(''); }} />
      {msg && <div className="toast">{msg}</div>}
      {modalKind && modalKind !== 'edit-planting' && <ActionModal kind={modalKind} data={data} onClose={() => setModal(null)} onSubmit={submitAction} />}
      {modalKind === 'edit-planting' && <PlantingEditModal planting={modal.planting} data={data} onClose={() => setModal(null)} onSubmit={async (form) => { await actions.updatePlanting(modal.planting.id, form); setModal(null); }} />}
      {tab === 'dashboard' && <Dashboard data={data} actions={actions} />}
      {tab !== 'dashboard' && <SecondaryPage tab={tab} data={data} actions={actions} />}
    </main>
  </div>;
}

function AuthPage({onLogin}) {
  const [mode, setMode] = useState('login');
  const [login, setLogin] = useState({email: '', password: ''});
  const [form, setForm] = useState({ownerName: '', farmName: '', phone: '', email: '', region: '', landArea: '', businessScale: '', comment: ''});
  const [status, setStatus] = useState('');
  const submitLogin = async (e) => { e.preventDefault(); const r = await post('/auth/login', login); onLogin(r); };
  const submitApplication = async (e) => { e.preventDefault(); const r = await post('/public/applications', form); setStatus(r.message || 'Заявка принята'); setForm({ownerName: '', farmName: '', phone: '', email: '', region: '', landArea: '', businessScale: '', comment: ''}); };
  const set = (key, value) => setForm(prev => ({...prev, [key]: value}));
  return <main className="auth-page">
    <section className="auth-hero"><div className="auth-brand"><div className="logo"><FaLeaf /></div><span>AgroCRM</span></div><h1>CRM для фермеров — доступ выдаётся после заявки</h1><p>Мы собираем данные о хозяйстве, оформляем профиль фермы и выдаём владельцу личный логин и пароль.</p><div className="auth-points"><span><FiCheck/>Профиль под ваше хозяйство</span><span><FiCheck/>Учёт земли, посевов и склада</span><span><FiCheck/>Аналитика прибыли и продаж</span></div></section>
    <section className="auth-grid single">
      <div className="auth-card auth-switch-card"><div className="auth-switch"><button className={mode === 'login' ? 'active' : ''} onClick={() => setMode('login')}>Вход</button><button className={mode === 'request' ? 'active' : ''} onClick={() => setMode('request')}>Заявка на доступ</button></div>{mode === 'login' ? <form className="login-card" onSubmit={submitLogin}><span className="eyebrow">Уже есть доступ</span><h2>Вход в CRM</h2><label><FiMail/><input value={login.email} onChange={e=>setLogin({...login,email:e.target.value})} placeholder="Логин / email" /></label><label><FiLock/><input value={login.password} onChange={e=>setLogin({...login,password:e.target.value})} type="password" placeholder="Пароль" /></label><button className="auth-primary">Войти</button><button type="button" className="auth-demo" onClick={()=>onLogin({farmId:1,name:'Демо'})}>Войти в демо</button><small>Логин и пароль выдаёт команда AgroCRM после подключения.</small></form> : <form className="request-card" onSubmit={submitApplication}><span className="eyebrow">Нужен доступ</span><h2>Заявка на подключение</h2><div className="request-grid"><label><FiUser/><input required value={form.ownerName} onChange={e=>set('ownerName',e.target.value)} placeholder="ФИО предпринимателя" /></label><label><FaLeaf/><input value={form.farmName} onChange={e=>set('farmName',e.target.value)} placeholder="Название хозяйства" /></label><label><FiPhone/><input required value={form.phone} onChange={e=>set('phone',e.target.value)} placeholder="Телефон" /></label><label><FiMail/><input value={form.email} onChange={e=>set('email',e.target.value)} placeholder="Почта" /></label><label><FiMapPin/><input value={form.region} onChange={e=>set('region',e.target.value)} placeholder="Регион" /></label><label><GiFarmTractor/><input value={form.landArea} onChange={e=>set('landArea',e.target.value)} placeholder="Масштаб земли, например 20 га" /></label></div><select value={form.businessScale} onChange={e=>set('businessScale',e.target.value)}><option value="">Формат хозяйства</option><option>Личное подсобное хозяйство</option><option>ИП / малый фермер</option><option>Среднее хозяйство</option><option>Агробизнес с продажами</option></select><textarea value={form.comment} onChange={e=>set('comment',e.target.value)} placeholder="Что выращиваете и какие задачи хотите закрыть?" />{status && <div className="request-status"><FiCheck/>{status}</div>}<button className="auth-primary">Отправить заявку</button></form>}</div>
    </section>
  </main>;
}

function Topbar({farm, me, onLogout}) { return <header className="topbar"><div className="left"><FiMenu /><b>{farm?.name || 'Ферма Ахмат'}</b><FiChevronDown /><span><FiMapPin />{farm?.region || 'Чеченская Республика'}</span></div><label className="search"><FiSearch /><input placeholder="Найти поле, клиента или культуру..." /><kbd>⌘K</kbd></label><div className="right"><div className="bell"><FiBell /><i>3</i></div><FiHelpCircle /><div className="avatar"><FaRegUser /></div><p><b>{me?.name || 'Ахмат Исаев'}</b><span>{me?.role === 'owner' ? 'Владелец' : (me?.role || 'Пользователь')}</span></p><button className="logout-btn" onClick={onLogout}>Выйти</button></div></header> }

function Dashboard({data, actions}) {
  const inv = data.inventory || [];
  const tasks = data.tasks || [];
  const sales = data.sales || [];
  const potato = inv.find(i => i.type === 'harvest');
  const seed = inv.find(i => i.type === 'seed');
  const revenue = num(data.dashboard?.revenue, sales.length ? 35000 : 0);
  const profit = num(data.dashboard?.profit, sales.length ? 20000 : 0);
  const potatoKg = num(potato?.quantity_kg, potato ? 0 : 4800);
  const seedKg = num(seed?.quantity_kg, 700);
  return <>
    <SeasonBanner seedKg={seedKg} potatoKg={potatoKg} />
    <section className="kpis">
      <Kpi icon={<FaRubleSign />} color="green" title="Выручка за сезон" value={`${revenue.toLocaleString('ru-RU')} ₽`} hint="+12% к прошлому сезону" />
      <Kpi icon={<FaChartLine />} color="green" title="Прибыль" value={`${profit.toLocaleString('ru-RU')} ₽`} hint="+15% к прошлому сезону" />
      <Kpi icon={<FaBoxesStacked />} color="green" title="Остаток урожая" value={`${potatoKg.toLocaleString('ru-RU')} кг`} hint="Доступно для продажи" />
      <Kpi icon={<GiSprout />} color="orange" title="Остаток семян" value={`${seedKg.toLocaleString('ru-RU')} кг`} hint="Ниже минимума!" danger />
      <Kpi icon={<FaClipboardCheck />} color="green" title="Ближайшие задачи" value={tasks.length || 4} hint="Требуют внимания" />
      <Kpi icon={<MdInventory2 />} color="violet" title="Внешние заказы" value="2" hint="Новые заказы" />
    </section>
    <WeatherOverview weather={data.weather} farm={data.farm} />
    <section className="dashboard-grid">
      <TasksCard tasks={tasks} onMore={() => actions.goTo('tasks')} />
      <InventoryCard potatoKg={potatoKg} seedKg={seedKg} onMore={() => actions.goTo('inventory')} />
      <AlertsCard onMore={() => actions.goTo('inventory')} />
      <PlantingsCard plantings={(data.plantings || []).filter(p => p.status !== 'harvested')} onMore={() => actions.goTo('plantings')} />
      <SalesCard onMore={() => actions.goTo('sales')} />
      <ProfitCard profit={profit} onMore={() => actions.goTo('analytics')} />
    </section>
    <QuickActions actions={actions} />
  </>;
}

function SeasonBanner({seedKg, potatoKg}) { return <section className="season-banner"><div><span className="eyebrow">Сезон картофеля · май 2026</span><h1>Картофельная партия под контролем: от 2 гектаров до первой продажи</h1><p>Главный экран показывает только то, что фермеру нужно решить сегодня: хватит ли семян, что делать на поле и сколько продукции уже можно продавать.</p></div><div className="field-ticket"><span>Поле №1</span><b>2 га</b><small>Грозненский район</small><hr/><p><GiSprout /> Семена: {seedKg} кг</p><p><GiPotato /> Товарный картофель: {potatoKg.toLocaleString('ru-RU')} кг</p></div></section> }

function Kpi({icon, color, title, value, hint, danger}) { return <article className="kpi"><div className={`round ${color}`}>{icon}</div><div><span>{title}</span><strong>{value}</strong><small className={danger ? 'danger' : ''}>{danger && '⚠ '}{hint}</small></div></article> }
function WeatherOverview({weather, farm}) { const days = weather?.daily || []; return <section className="weather-hero"><div className="weather-main"><span className="eyebrow">Погодные условия на ферме</span><h2>{weather ? `${weather.icon} ${weather.label}` : 'Погода обновляется...'}</h2><p>{farm?.name || 'Ферма'} · {weather?.location || farm?.region || 'Чеченская Республика'}</p><div className="weather-metrics"><article><b>{weather?.currentTemp ?? '—'}°C</b><span>Сейчас</span></article><article><b>{weather?.wind ?? '—'} км/ч</b><span>Ветер</span></article><article><b>{weather?.humidity ?? '—'}%</b><span>Влажность</span></article></div></div><div className="weather-forecast">{days.length ? days.map(item => <div key={item.day} className="weather-day"><span>{formatDate(item.day)}</span><b>{Math.round(num(item.max))}° / {Math.round(num(item.min))}°</b><small>Осадки: {item.rain ?? 0}%</small></div>) : <div className="weather-day"><span>Нет данных</span><b>—</b><small>Попробуйте позже</small></div>}</div></section> }
function TasksCard({tasks, onMore}) { const rows = (tasks||[]).slice(0,4); return <Panel title="Ближайшие задачи">{rows.length?rows.map(task => <div className="list-row" key={task.id}><div className="mini blue"><FaClipboardCheck /></div><p><b>{task.title}</b><span>{task.planting_id?`Посев #${task.planting_id}`:'Общая задача'}</span></p><time>{formatDate(task.due_date)}</time><em>{task.status==='done'?'Выполнено':'В работе'}</em></div>):<div className="list-row"><p><b>Нет задач</b></p></div>}<More onClick={onMore}>Смотреть все задачи</More></Panel> }
function InventoryCard({potatoKg, seedKg, onMore}) { const rows = [[<GiPotato/>, 'Картофель товарный', 'Урожай', `${potatoKg.toLocaleString('ru-RU')} кг`, 'Доступно'], [<GiPotato/>, 'Семена картофеля', 'Семена', `${seedKg.toLocaleString('ru-RU')} кг`, 'Низкий остаток'], [<GiFertilizerBag/>, 'Удобрение NPK', 'Удобрения', '50 кг', 'В норме']]; return <Panel title="Склад: остатки">{rows.map(r => <div className="stock-row" key={r[1]}><div className="emoji">{r[0]}</div><p><b>{r[1]}</b><span>{r[2]}</span></p><strong>{r[3]}</strong><em className={r[4].startsWith('Низкий') ? 'low' : ''}>{r[4]}</em></div>)}<More onClick={onMore}>Перейти на склад</More></Panel> }
function AlertsCard({onMore}) { const rows = [[MdWarningAmber, 'Низкий остаток семян картофеля', 'Осталось 200 кг, минимум 300 кг', 'warn'], [MdWarningAmber, 'Рекомендуется закупка удобрений', 'Остаток 50 кг, минимум 100 кг', 'warn'], [MdInfoOutline, '2 новых внешних заказа', 'Требуют обработки менеджером', 'info']]; return <Panel title="Предупреждения">{rows.map(([I,t,s,cls]) => <div className={`alert ${cls}`} key={t}><I /><p><b>{t}</b><span>{s}</span></p><FiChevronRight /></div>)}<More onClick={onMore}>Все уведомления</More></Panel> }
function PlantingsCard({plantings = [], onMore}) { const rows = plantings.slice(0, 3); return <Panel title="Активные посевы"><table><thead><tr><th>Культура</th><th>Поле</th><th>Семена</th><th>Ожидаемый урожай</th><th>Статус</th></tr></thead><tbody>{rows.length ? rows.map(row => {const meta = plantingStatusMeta(row.status); return <tr key={row.id}><td><span className="crop-cell"><CropIcon type={cropTypeFromName(row.crop_name)} />{row.crop_name || '—'}</span></td><td>{row.field_name || '—'}</td><td>{formatKg(row.seed_quantity_kg)}</td><td>{formatKg(row.expected_yield_kg)}</td><td><em>{meta.label}</em></td></tr>}) : <tr><td colSpan="5">Посевов пока нет</td></tr>}</tbody></table><More onClick={onMore}>Все посевы</More></Panel> }
function SalesCard({onMore}) { return <Panel title="Продажи за сезон"><table><thead><tr><th>Клиент</th><th>Товар</th><th>Кол-во</th><th>Сумма</th><th>Статус</th></tr></thead><tbody><tr><td>Ресторан Кавказ</td><td>Картофель</td><td>1 000 кг</td><td>35 000 ₽</td><td><em>Оплачено</em></td></tr></tbody></table><More onClick={onMore}>Все продажи</More></Panel> }
function ProfitCard({profit, onMore}) { return <Panel title="Прибыль по культурам"><div className="donut"><div><b>{profit.toLocaleString('ru-RU')} ₽</b><span>Общая прибыль</span></div></div><ul className="legend"><li><i></i>Картофель <b>20 000 ₽ (66%)</b></li><li><i></i>Помидоры <b>8 000 ₽ (26%)</b></li><li><i></i>Огурцы <b>3 000 ₽ (8%)</b></li></ul><More onClick={onMore}>Полная аналитика</More></Panel> }
function QuickActions({actions}) { return <section className="quick"><b>Быстрые действия</b><button onClick={()=>actions.open('field')}><FiPlus />Добавить поле</button><button onClick={actions.planting}><FiPlus />Создать посев</button><button onClick={actions.harvest}><FiPlus />Добавить урожай</button><button onClick={()=>actions.open('customer')}><FiPlus />Добавить клиента</button><button onClick={actions.sale}><FaCartShopping />Новая продажа</button><button onClick={()=>actions.open('inventory')}><GiPlantRoots />Закупка семян</button></section> }
function Panel({title, children}) { return <article className="panel"><h3>{title}</h3>{children}</article> }
function More({children, onClick}) { return <button className="more" onClick={onClick}>{children}<FiChevronRight /></button> }
function FieldStats() { const stats = [[GiFarmTractor, 'Всего полей', '6', 'на ферме'], [FaLeaf, 'Общая площадь', '15.7 га', 'все поля'], [GiSprout, 'Засеяно', '8.2 га', '52% от общей площади'], [FaClipboardCheck, 'Готово к посеву', '5.5 га', '35% от общей площади'], [FiRefreshCw, 'Отдыхает', '2.0 га', '13% от общей площади']]; return <section className="field-stats">{stats.map(([Icon, title, value, hint]) => <article className="field-stat" key={title}><div><Icon /></div><p><span>{title}</span><b>{value}</b><small>{hint}</small></p></article>)}</section> }
function FieldsPage({data, actions}) { const [q,setQ]=useState(''); const [status,setStatus]=useState('all'); const [menu,setMenu]=useState(null); const [edit,setEdit]=useState(null); const fields=data.fields||[]; const statusMap={ready:['Готово к посеву','ready'],planted:['Занято посевом','seeded'],resting:['Отдыхает','rest']}; const visible=fields.filter(f=>`${f.name} ${f.location} ${f.soil_type}`.toLowerCase().includes(q.toLowerCase())).filter(f=>status==='all'||f.status===status); return <div className="fields-page"><div className="page-head"><div><h1>Поля</h1><p>Управление вашими полями и участками</p></div><button className="add-field" onClick={()=>actions.open('field')}><FiPlus />Добавить поле</button></div><FieldStats /><section className="fields-card"><div className="fields-toolbar"><div className="tabs"><button className={status==='all'?'active':''} onClick={()=>setStatus('all')}>Все поля</button><button className={status==='planted'?'active':''} onClick={()=>setStatus('planted')}>Активные</button><button className={status==='ready'?'active':''} onClick={()=>setStatus('ready')}>Готовы к посеву</button><button className={status==='resting'?'active':''} onClick={()=>setStatus('resting')}>Отдыхает</button></div><div className="field-controls"><label><FiSearch /><input value={q} onChange={e=>setQ(e.target.value)} placeholder="Поиск по полям..." /></label><button onClick={()=>setStatus('all')}><FiFilter />Сбросить</button><select value={status} onChange={e=>setStatus(e.target.value)}><option value="all">Все статусы</option><option value="ready">Готово к посеву</option><option value="planted">Занято посевом</option><option value="resting">Отдыхает</option></select></div></div><table className="fields-table"><thead><tr><th>Название поля</th><th>Площадь</th><th>Местоположение</th><th>Тип почвы</th><th>Статус</th><th>Последняя активность</th><th>Действия</th></tr></thead><tbody>{visible.map((f, idx) => {const st=statusMap[f.status]||statusMap.ready; return <tr key={f.id}><td><div className="field-name"><div className={`field-thumb f${idx%6+1}`}></div><p><b>{f.name}</b></p></div></td><td>{Number(f.area_hectares||0)} га</td><td>{f.location||'—'}</td><td>{f.soil_type||'—'}</td><td><span className={`field-badge ${st[1]}`}>{st[0]}</span></td><td>{f.updated_at?'Обновлено':'—'}</td><td className="field-actions-cell"><button className="icon-action" onClick={()=>setMenu(menu===f.id?null:f.id)}><FiMoreHorizontal /></button>{menu===f.id&&<div className="row-menu"><button onClick={()=>{setEdit(f);setMenu(null)}}>Изменить</button><button className="danger" onClick={()=>{if(confirm(`Удалить ${f.name}?`)) actions.deleteField(f.id); setMenu(null)}}>Удалить</button></div>}</td></tr>})}</tbody></table><div className="field-footer"><span>Показано {visible.length} из {fields.length} полей</span><div><button><FiChevronLeft /></button><button className="current">1</button><button><FiChevronRight /></button></div></div></section>{edit&&<FieldEditModal field={edit} onClose={()=>setEdit(null)} onSubmit={async form=>{await actions.updateField(edit.id,form);setEdit(null)}}/>}</div> }
function FieldEditModal({field,onClose,onSubmit}){const [form,setForm]=useState({name:field.name||'',areaHectares:field.area_hectares||'',location:field.location||'',soilType:field.soil_type||'',status:field.status||'ready'});const set=(k,v)=>setForm(p=>({...p,[k]:v}));return <div className="modal-backdrop" role="dialog" aria-modal="true"><form className="action-modal" onSubmit={e=>{e.preventDefault();onSubmit(form)}}><button type="button" className="modal-close" onClick={onClose}><FiChevronDown/></button><h2>Изменить поле</h2><p>Обновите данные участка</p><div className="modal-grid"><label><span>Название поля *</span><input value={form.name} onChange={e=>set('name',e.target.value)}/></label><label><span>Площадь, га</span><input type="number" value={form.areaHectares} onChange={e=>set('areaHectares',e.target.value)}/></label><label><span>Местоположение</span><input value={form.location} onChange={e=>set('location',e.target.value)}/></label><label><span>Статус</span><select value={form.status} onChange={e=>set('status',e.target.value)}><option value="ready">Готово к посеву</option><option value="planted">Занято посевом</option><option value="resting">Отдыхает</option></select></label><label><span>Тип почвы</span><input value={form.soilType} onChange={e=>set('soilType',e.target.value)}/></label></div><div className="modal-actions"><button type="button" onClick={onClose}>Отмена</button><button className="save-settings">Сохранить</button></div></form></div>}
function PlantingStats({plantings = []}) { const active = plantings.filter(p => p.status === 'active').length; const harvested = plantings.filter(p => p.status === 'harvested').length; const planned = plantings.filter(p => p.status === 'planned').length; const expected = plantings.reduce((sum, p) => sum + num(p.expected_yield_kg), 0); const crops = new Set(plantings.map(p => p.crop_name).filter(Boolean)).size; const stats = [[GiWheat, 'Активных посевов', String(active), `Планируемых: ${planned}`, 'green'], [FaLeaf, 'Всего посевов', String(plantings.length), 'Все сезоны', 'green'], [FaClipboardCheck, 'Ожидаемый урожай', formatKg(expected), 'По всем посевам', 'orange'], [GiPlantRoots, 'Завершено', String(harvested), 'Уже собранные посевы', 'green'], [MdInventory2, 'Культур выращивается', String(crops), 'Уникальные культуры', 'violet']]; return <section className="planting-stats">{stats.map(([Icon, title, value, hint, color]) => <article className="planting-stat" key={title}><div className={color}><Icon /></div><p><span>{title}</span><b>{value}</b><small>{hint}</small></p></article>)}</section> }
function CropIcon({type}) { const icons = {potato: GiPotato, tomato: GiTomato, cucumber: GiPlantRoots, wheat: GiGrain, onion: GiSprout, corn: GiCorn, carrot: GiCarrot}; const I = icons[type] || GiSprout; return <I /> }
function Progress({label, value}) { return <div className="progress-cell"><span>{label}</span><div><i style={{width: `${value}%`}}></i></div><b>{value}%</b></div> }
function PlantingsPage({data, actions}) { const plantings = data.plantings || []; const tasks = data.tasks || []; const inventory = data.inventory || []; const [q, setQ] = useState(''); const [status, setStatus] = useState('all'); const [menu, setMenu] = useState(null); const [selectedId, setSelectedId] = useState(plantings[0]?.id || null); useEffect(() => { if (!plantings.some(p => p.id === selectedId)) setSelectedId(plantings[0]?.id || null); }, [plantings, selectedId]); const visible = plantings.filter(p => `${p.crop_name || ''} ${p.field_name || ''}`.toLowerCase().includes(q.toLowerCase())).filter(p => status === 'all' || plantingStatusMeta(p.status).filter === status); const selected = plantings.find(p => p.id === selectedId) || visible[0] || plantings[0] || null; return <div className="plantings-page"><div className="page-head"><div><h1>Посевы</h1><p>Управление посевами и культурами на ваших полях</p></div><div className="head-actions"><button onClick={() => actions.exportXLSX('plantings')}><FiDownload />Экспорт XLSX</button><button onClick={() => { setQ(''); setStatus('all'); }}><FiFilter />Сбросить фильтры</button><button className="add-field" onClick={actions.planting}><FiPlus />Создать посев</button></div></div><PlantingStats plantings={plantings} /><div className="planting-layout"><section className="plantings-card"><div className="fields-toolbar"><div className="tabs"><button className={status==='all'?'active':''} onClick={()=>setStatus('all')}>Все посевы</button><button className={status==='active'?'active':''} onClick={()=>setStatus('active')}>Активные</button><button className={status==='planned'?'active':''} onClick={()=>setStatus('planned')}>Планируемые</button><button className={status==='harvested'?'active':''} onClick={()=>setStatus('harvested')}>Завершенные</button><button className={status==='cancelled'?'active':''} onClick={()=>setStatus('cancelled')}>Отмененные</button></div><div className="field-controls"><label><FiSearch /><input value={q} onChange={e=>setQ(e.target.value)} placeholder="Поиск по культуре, полю..." /></label><select value={status} onChange={e=>setStatus(e.target.value)}><option value="all">Все статусы</option><option value="active">Активные</option><option value="planned">Планируемые</option><option value="harvested">Завершенные</option><option value="cancelled">Отмененные</option></select></div></div><table className="plantings-table"><thead><tr><th>Культура</th><th>Поле</th><th>Дата посадки</th><th>Семена (кг)</th><th>Ожидаемый урожай</th><th>Статус</th><th>Прогресс</th><th>Действия</th></tr></thead><tbody>{visible.length ? visible.map((row) => { const meta = plantingStatusMeta(row.status); const progress = plantingProgress(row); const isSelected = selected?.id === row.id; return <tr key={row.id} className={isSelected ? 'row-selected' : ''} onClick={() => setSelectedId(row.id)}><td><span className={`crop-icon ${cropTypeFromName(row.crop_name)}`}><CropIcon type={cropTypeFromName(row.crop_name)} /></span>{row.crop_name || '—'}</td><td>{row.field_name || '—'}</td><td>{formatDate(row.planting_date)}</td><td>{formatKg(row.seed_quantity_kg)}</td><td>{formatKg(row.expected_yield_kg)}</td><td><span className={`planting-badge ${meta.cls}`}>{meta.label}</span></td><td><Progress label={plantingStageLabel(progress, row.status)} value={progress} /></td><td className="field-actions-cell"><button className="icon-action" onClick={(e)=>{e.stopPropagation();setSelectedId(row.id);}}><FiEye /></button><button className="icon-action" onClick={(e)=>{e.stopPropagation();setMenu(menu===row.id?null:row.id)}}><FiMoreHorizontal /></button>{menu===row.id&&<div className="row-menu"><button onClick={()=>{actions.openPlantingEdit(row);setMenu(null);}}>Изменить</button>{row.status !== 'harvested' && <button onClick={async ()=>{await actions.completePlanting(row.id);setMenu(null);}}>Завершить</button>}<button className="danger" onClick={async ()=>{if(confirm(`Удалить посев ${row.crop_name || ''}?`)){await actions.deletePlanting(row.id);} setMenu(null);}}>Удалить</button></div>}</td></tr>}) : <tr><td colSpan="8">Нет посевов по выбранным фильтрам</td></tr>}</tbody></table><div className="field-footer"><span>Показано {visible.length} из {plantings.length} посевов</span><div><button><FiChevronLeft /></button><button className="current">1</button><button><FiChevronRight /></button></div></div></section><PlantingDetails planting={selected} tasks={tasks} inventory={inventory} /></div></div> }
function PlantingDetails({planting, tasks = [], inventory = []}) { if (!planting) return <aside className="planting-details"><h2>Нет данных</h2><p>Создайте первый посев, чтобы увидеть детали.</p></aside>; const meta = plantingStatusMeta(planting.status); const linkedTasks = tasks.filter(t => t.planting_id === planting.id).slice(0, 4); const seedItem = inventory.find(i => i.type === 'seed' && i.crop_id === planting.crop_id); const leftSeed = num(seedItem?.quantity_kg); const usedSeed = num(planting.seed_quantity_kg); const totalSeed = leftSeed + usedSeed; const usedPercent = totalSeed > 0 ? Math.round((usedSeed / totalSeed) * 100) : 0; return <aside className="planting-details"><h2>{planting.crop_name || 'Посев'} на {planting.field_name || 'поле'}</h2><span className={`planting-badge ${meta.cls}`}>{meta.label}</span><hr/><h3>Общая информация</h3><dl><dt>Культура</dt><dd>{planting.crop_name || '—'}</dd><dt>Поле</dt><dd>{planting.field_name || '—'}</dd><dt>Дата посадки</dt><dd>{formatDate(planting.planting_date)}</dd><dt>План сбора</dt><dd>{formatDate(planting.planned_harvest_date)}</dd><dt>Семена использовано</dt><dd>{formatKg(planting.seed_quantity_kg)}</dd><dt>Ожидаемый урожай</dt><dd>{formatKg(planting.expected_yield_kg)}</dd></dl><h3>Использование семян</h3><div className="seed-donut"><div></div></div><ul className="seed-legend"><li><i></i>Списано <b>{formatKg(usedSeed)} ({usedPercent}%)</b></li><li><i></i>Осталось на складе <b>{formatKg(leftSeed)} ({Math.max(0, 100 - usedPercent)}%)</b></li></ul><small>Всего по культуре: {formatKg(totalSeed)}</small><hr/><h3>Связанные задачи ({linkedTasks.length})</h3>{linkedTasks.length ? linkedTasks.map(task => <div className="linked-task" key={task.id}><b>{task.title}</b><span>{formatDate(task.due_date)}</span><em>{task.status === 'done' ? 'Выполнено' : task.status === 'in_progress' ? 'В процессе' : 'Запланировано'}</em></div>) : <div className="linked-task empty"><b>Нет связанных задач</b><span>Добавьте задачи для этого посева</span></div>}<More>Все задачи по посеву</More></aside> }
function PlantingEditModal({planting, data, onClose, onSubmit}){const fields=data.fields||[], crops=data.crops||[]; const [form,setForm]=useState({fieldID: planting.field_id || '', cropID: planting.crop_id || '', seedQuantityKg: planting.seed_quantity_kg || '', expectedYieldKg: planting.expected_yield_kg || '', status: planting.status || 'active', plantingDate: planting.planting_date ? String(planting.planting_date).slice(0,10) : '', plannedHarvestDate: planting.planned_harvest_date ? String(planting.planned_harvest_date).slice(0,10) : ''}); const set=(k,v)=>setForm(p=>({...p,[k]:v})); return <div className="modal-backdrop" role="dialog" aria-modal="true"><form className="action-modal" onSubmit={e=>{e.preventDefault();onSubmit(form)}}><button type="button" className="modal-close" onClick={onClose}><FiChevronDown/></button><h2>Изменить посев</h2><p>Обновите поле, культуру, даты и расход семян</p><div className="modal-grid"><label><span>Поле *</span><select value={form.fieldID} onChange={e=>set('fieldID', e.target.value)}>{fields.map(f => <option key={f.id} value={f.id}>{f.name}</option>)}</select></label><label><span>Культура *</span><select value={form.cropID} onChange={e=>set('cropID', e.target.value)}>{crops.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}</select></label><label><span>Дата посадки</span><input type="date" value={form.plantingDate} onChange={e=>set('plantingDate', e.target.value)} /></label><label><span>План сбора</span><input type="date" value={form.plannedHarvestDate} onChange={e=>set('plannedHarvestDate', e.target.value)} /></label><label><span>Семена, кг *</span><input type="number" value={form.seedQuantityKg} onChange={e=>set('seedQuantityKg', e.target.value)} /></label><label><span>Ожидаемый урожай, кг</span><input type="number" value={form.expectedYieldKg} onChange={e=>set('expectedYieldKg', e.target.value)} /></label><label><span>Статус</span><select value={form.status} onChange={e=>set('status', e.target.value)}><option value="active">Активный</option><option value="planned">Планируемый</option><option value="harvested">Завершен</option><option value="cancelled">Отменен</option></select></label></div><div className="modal-actions"><button type="button" onClick={onClose}>Отмена</button><button className="save-settings">Сохранить</button></div></form></div>}
function InventoryStats({items = []}) { const seeds = items.filter(i => i.type === 'seed'); const harvest = items.filter(i => i.type === 'harvest'); const fertilizers = items.filter(i => i.type === 'fertilizer'); const low = items.filter(i => num(i.quantity_kg) <= num(i.min_quantity_kg)).length; const stats = [[MdInventory2,'Общий остаток',formatKg(items.reduce((s,i)=>s+num(i.quantity_kg),0)),'Все товары на складе','green'],[GiSprout,'Семена',formatKg(seeds.reduce((s,i)=>s+num(i.quantity_kg),0)),`${seeds.length} позиций`,'green'],[GiPlantRoots,'Продукция',formatKg(harvest.reduce((s,i)=>s+num(i.quantity_kg),0)),`${harvest.length} позиций`,'green'],[GiFertilizerBag,'Удобрения',formatKg(fertilizers.reduce((s,i)=>s+num(i.quantity_kg),0)),`${fertilizers.length} позиций`,'green'],[MdWarningAmber,'Низкий остаток',String(low),'Требуют внимания','orange']]; return <section className="inventory-stats">{stats.map(([Icon,t,v,h,c])=><article className="inventory-stat" key={t}><div className={c}><Icon/></div><p><span>{t}</span><b>{v}</b><small>{h}</small></p></article>)}</section> }
function InventoryPage({data, actions}) { const items=data.inventory||[]; const [q,setQ]=useState(''); const [type,setType]=useState('all'); const [menu,setMenu]=useState(null); const visible=items.filter(i=>`${i.name||''} ${i.type||''}`.toLowerCase().includes(q.toLowerCase())).filter(i=>type==='all'||i.type===type); return <div className="inventory-page"><div className="page-head"><div><h1>Склад</h1><p>Управление остатками семян, удобрений и продукции</p></div><div className="head-actions"><button onClick={()=>actions.exportXLSX('inventory')}><FiDownload/>Экспорт XLSX</button><button onClick={()=>actions.importData('inventory')}><FiUpload/>Импорт XLSX</button><button onClick={async ()=>{const id=prompt('ID позиции'); const delta=prompt('Корректировка в кг, можно отрицательное'); if(id&&delta) await actions.adjustInventory(Number(id), Number(delta));}}><FiPlus/>Корректировка остатков</button><button className="add-field" onClick={()=>actions.open('inventory')}><FiPlus/>Добавить товар</button></div></div><InventoryStats items={items}/><div className="inventory-layout"><section className="inventory-card"><div className="fields-toolbar"><div className="tabs"><button className={type==='all'?'active':''} onClick={()=>setType('all')}>Все товары</button><button className={type==='seed'?'active':''} onClick={()=>setType('seed')}>Семена</button><button className={type==='harvest'?'active':''} onClick={()=>setType('harvest')}>Продукция</button><button className={type==='fertilizer'?'active':''} onClick={()=>setType('fertilizer')}>Удобрения</button><button className={type==='other'?'active':''} onClick={()=>setType('other')}>Прочее</button></div><div className="field-controls"><label><FiSearch/><input value={q} onChange={e=>setQ(e.target.value)} placeholder="Поиск по товарам..."/></label><select value={type} onChange={e=>setType(e.target.value)}><option value="all">Все категории</option><option value="seed">Семена</option><option value="harvest">Продукция</option><option value="fertilizer">Удобрения</option><option value="other">Прочее</option></select></div></div><table className="inventory-table"><thead><tr><th>Товар</th><th>Категория</th><th>Количество</th><th>Ед. изм.</th><th>Мин. остаток</th><th>Средняя цена</th><th>Статус</th><th>Действия</th></tr></thead><tbody>{visible.length?visible.map((item)=><tr key={item.id}><td><div className="item-name"><span className={`item-icon ${cropTypeFromName(item.name)}`}><CropIcon type={cropTypeFromName(item.name)}/></span><p><b>{item.name}</b>{item.crop_id&&<small>ID культуры: {item.crop_id}</small>}</p></div></td><td><span className={`category ${item.type==='seed'?'Семена':item.type==='harvest'?'Продукция':item.type==='fertilizer'?'Удобрения':'Прочее'}`}>{item.type==='seed'?'Семена':item.type==='harvest'?'Продукция':item.type==='fertilizer'?'Удобрения':'Прочее'}</span></td><td>{num(item.quantity_kg).toLocaleString('ru-RU')}</td><td>{item.unit||'кг'}</td><td>{formatKg(item.min_quantity_kg)}</td><td>{num(item.average_cost_per_kg).toLocaleString('ru-RU')} ₽</td><td><span className={`stock-status ${num(item.quantity_kg)<=num(item.min_quantity_kg)?'low':'ok'}`}>{num(item.quantity_kg)<=num(item.min_quantity_kg)?'Низкий остаток':'В наличии'}</span></td><td className="field-actions-cell"><button className="icon-action" onClick={()=>setMenu(menu===item.id?null:item.id)}><FiMoreHorizontal/></button>{menu===item.id&&<div className="row-menu"><button onClick={async ()=>{const name=prompt('Название', item.name); if(name!==null) await actions.updateInventory(item.id,{name}); setMenu(null);}}>Переименовать</button><button onClick={async ()=>{const delta=prompt('Корректировка, кг'); if(delta!==null) await actions.adjustInventory(item.id, Number(delta)); setMenu(null);}}>Скорректировать</button><button className="danger" onClick={async ()=>{if(confirm(`Удалить ${item.name}?`)) await actions.deleteInventory(item.id); setMenu(null);}}>Удалить</button></div>}</td></tr>):<tr><td colSpan="8">Нет товаров по выбранным фильтрам</td></tr>}</tbody></table><div className="field-footer"><span>Показано {visible.length} из {items.length} товаров</span><div><button><FiChevronLeft/></button><button className="current">1</button><button><FiChevronRight/></button></div></div></section><InventorySide items={items}/></div></div> }
function InventorySide({items=[]}){const low=items.filter(i=>num(i.quantity_kg)<=num(i.min_quantity_kg)).slice(0,3); return <aside className="inventory-side"><section><h3>Обзор склада</h3><div className="warehouse-donut"><div><b>{items.reduce((s,i)=>s+num(i.quantity_kg),0).toLocaleString('ru-RU')}</b><span>кг</span></div></div><ul className="warehouse-legend"><li><i></i><p>Продукция<span>{formatKg(items.filter(i=>i.type==='harvest').reduce((s,i)=>s+num(i.quantity_kg),0))}</span></p></li><li><i></i><p>Семена<span>{formatKg(items.filter(i=>i.type==='seed').reduce((s,i)=>s+num(i.quantity_kg),0))}</span></p></li><li><i></i><p>Удобрения<span>{formatKg(items.filter(i=>i.type==='fertilizer').reduce((s,i)=>s+num(i.quantity_kg),0))}</span></p></li></ul></section><section><div className="side-title"><h3>Низкий остаток</h3><button>{low.length}</button></div>{low.length?low.map(x=><div className="low-row" key={x.id}><span className={`item-icon ${cropTypeFromName(x.name)}`}><CropIcon type={cropTypeFromName(x.name)}/></span><p><b>{x.name}</b><small>Минимум {formatKg(x.min_quantity_kg)}</small></p><em>{formatKg(x.quantity_kg)}</em></div>):<div className="low-row"><p><b>Все в норме</b></p></div>}</section></aside>}
function HarvestStats({rows=[]}){const soldKg=(rows||[]).reduce((s,r)=>s+num(r.quantity_kg),0); const unique=new Set((rows||[]).map(r=>r.crop_name).filter(Boolean)).size; const stats=[[GiPlantRoots,'Всего собрано',formatKg(soldKg),'в этом сезоне'],[FaStore,'Записей урожая',String(rows.length),'в базе'],[MdLocalShipping,'Культур',String(unique),'уникальных'],[FaChartLine,'Последний сбор',rows[0]?formatDate(rows[0].harvest_date):'—','последняя запись']];return <section className="harvest-stats">{stats.map(([Icon,t,v,h])=><article className="harvest-stat" key={t}><div><Icon/></div><p><span>{t}</span><b>{v}</b><small>{h}</small></p></article>)}</section>}
function HarvestPage({data,actions}){const rows=data.harvests||[]; const [q,setQ]=useState(''); const [menu,setMenu]=useState(null); const visible=rows.filter(r=>`${r.crop_name||''}`.toLowerCase().includes(q.toLowerCase())); return <div className="harvest-page"><div className="page-head"><div><h1>Урожай</h1><p>Учет собранного урожая с полей и его перемещение на склад</p></div><div className="head-actions"><button onClick={()=>actions.exportXLSX('harvests')}><FiDownload/>Экспорт XLSX</button><button onClick={()=>actions.exportRows('harvests.csv', [['Культура','Дата','Количество кг','Качество'], ...rows.map(r=>[r.crop_name, r.harvest_date, r.quantity_kg, r.quality_grade])])}><FiDownload/>Экспорт CSV</button><button className="add-field" onClick={actions.harvest}><FiPlus/>Добавить урожай</button></div></div><HarvestStats rows={rows}/><section className="harvest-card"><div className="fields-toolbar"><div className="tabs"><button className="active">Все урожаи</button></div><div className="field-controls"><label><FiSearch/><input value={q} onChange={e=>setQ(e.target.value)} placeholder="Поиск по культуре..."/></label></div></div><table className="harvest-table"><thead><tr><th>Культура</th><th>Поле / Посев</th><th>Дата сбора</th><th>Количество</th><th>Качество</th><th>На склад</th><th>Статус</th><th>Действия</th></tr></thead><tbody>{visible.length?visible.map(r=><tr key={r.id}><td><div className="harvest-crop"><span className={`crop-icon ${cropTypeFromName(r.crop_name)}`}><CropIcon type={cropTypeFromName(r.crop_name)}/></span><p><b>{r.crop_name||'—'}</b><small>ID #{r.id}</small></p></div></td><td>{r.field_id?`Поле #${r.field_id}`:'—'}<br/><span>{r.planting_id?`Посев #${r.planting_id}`:'Без посева'}</span></td><td>{formatDate(r.harvest_date)}</td><td>{formatKg(r.quantity_kg)}</td><td><span className={`quality ${String(r.quality_grade||'').toLowerCase().includes('уд')?'mid':'good'}`}>{r.quality_grade||'—'}</span></td><td>{r.added_to_inventory_item_id?`Склад #${r.added_to_inventory_item_id}`:'—'}</td><td><span className="harvest-status ok">На складе</span></td><td className="field-actions-cell"><button className="icon-action" onClick={()=>setMenu(menu===r.id?null:r.id)}><FiMoreHorizontal/></button>{menu===r.id&&<div className="row-menu"><button onClick={async ()=>{const quality=prompt('Качество', r.quality_grade||''); if(quality!==null) await actions.updateHarvest(r.id,{qualityGrade: quality}); setMenu(null);}}>Качество</button><button className="danger" onClick={async ()=>{if(confirm('Удалить запись урожая?')) await actions.deleteHarvest(r.id); setMenu(null);}}>Удалить</button></div>}</td></tr>):<tr><td colSpan="8">Нет записей урожая</td></tr>}</tbody></table><div className="field-footer"><span>Показано {visible.length} из {rows.length} записей</span><div><button><FiChevronLeft/></button><button className="current">1</button><button><FiChevronRight/></button></div></div></section></div>}
function TaskIcon({type}){const icons={water:MdWaterDrop,check:FaLeaf,buy:FaCartShopping,treat:GiFertilizerBag,feed:GiSprout,prepare:GiFarmTractor,harvest:FiCheck};const I=icons[type]||FaClipboardCheck;return <I/>}
function TasksPage({data,actions}){const rows=data.tasks||[]; const [q,setQ]=useState(''); const [status,setStatus]=useState('all'); const [menu,setMenu]=useState(null); const visible=rows.filter(r=>`${r.title||''} ${r.description||''}`.toLowerCase().includes(q.toLowerCase())).filter(r=>status==='all'||r.status===status); return <div className="tasks-page"><div className="page-head"><div><h1>Задачи</h1><p>Планируйте и контролируйте работы на полях</p></div><button className="add-field" onClick={()=>actions.open('task')}><FiPlus/>Создать задачу</button></div><section className="tasks-card"><div className="fields-toolbar"><div className="tabs"><button className={status==='all'?'active':''} onClick={()=>setStatus('all')}>Все задачи</button><button className={status==='todo'?'active':''} onClick={()=>setStatus('todo')}>К выполнению</button><button className={status==='done'?'active':''} onClick={()=>setStatus('done')}>Выполненные</button></div><div className="field-controls"><label><FiSearch/><input value={q} onChange={e=>setQ(e.target.value)} placeholder="Поиск по задачам..."/></label><select value={status} onChange={e=>setStatus(e.target.value)}><option value="all">Все статусы</option><option value="todo">К выполнению</option><option value="done">Выполненные</option></select></div></div><table className="tasks-table"><thead><tr><th>Задача</th><th>Поле / Посев</th><th>Тип</th><th>Срок выполнения</th><th>Статус</th><th></th></tr></thead><tbody>{visible.length?visible.map(r=><tr key={r.id}><td><div className="task-name"><span className="task-icon"><TaskIcon type={r.type}/></span><p><b>{r.title}</b><small>{r.description||'Без описания'}</small></p></div></td><td>{r.field_id?`Поле #${r.field_id}`:'—'}<br/><span>{r.planting_id?`Посев #${r.planting_id}`:'Без посева'}</span></td><td><span className={`task-type ${r.type||'check'}`}>{r.type||'planting'}</span></td><td><b>{formatDate(r.due_date)}</b></td><td><span className={`task-status ${r.status==='done'?'planned':'process'}`}>{r.status==='done'?'Выполнено':'В работе'}</span></td><td className="field-actions-cell"><button className="icon-action" onClick={()=>setMenu(menu===r.id?null:r.id)}><FiMoreHorizontal/></button>{menu===r.id&&<div className="row-menu"><button onClick={async ()=>{const title=prompt('Название', r.title); if(title!==null) await actions.updateTask(r.id,{title}); setMenu(null);}}>Переименовать</button>{r.status!=='done'&&<button onClick={async ()=>{await actions.completeTask(r.id); setMenu(null);}}>Завершить</button>}<button className="danger" onClick={async ()=>{if(confirm('Удалить задачу?')) await actions.deleteTask(r.id); setMenu(null);}}>Удалить</button></div>}</td></tr>):<tr><td colSpan="6">Нет задач</td></tr>}</tbody></table><div className="field-footer"><span>Показано {visible.length} из {rows.length} задач</span><div><button><FiChevronLeft/></button><button className="current">1</button><button><FiChevronRight/></button></div></div></section></div>}
function CustomerStats(){const stats=[[FaUsers,'Всего клиентов','56','всего в базе'],[FaStore,'Активных клиентов','34','совершали заказы'],[FaCartShopping,'Заказов в этом месяце','18','на сумму 248 500 ₽'],[FaChartLine,'Общая выручка','2 156 800 ₽','за все время']];return <section className="customer-stats">{stats.map(([Icon,t,v,h])=><article className="customer-stat" key={t}><div><Icon/></div><p><span>{t}</span><b>{v}</b><small>{h}</small></p></article>)}</section>}
function CustomersPage({data,actions}){const rows=data.customers||[]; const [q,setQ]=useState(''); const [menu,setMenu]=useState(null); const visible=rows.filter(r=>`${r.name||''} ${r.phone||''} ${r.email||''}`.toLowerCase().includes(q.toLowerCase())); return <div className="customers-page"><div className="page-head"><div><h1>Клиенты</h1><p>Управление клиентами и их заказами</p></div><button className="add-field" onClick={()=>actions.open('customer')}><FiPlus/>Добавить клиента</button></div><CustomerStats/><section className="customers-card"><div className="fields-toolbar"><div className="tabs"><button className="active">Все клиенты</button></div><div className="field-controls"><label><FiSearch/><input value={q} onChange={e=>setQ(e.target.value)} placeholder="Поиск по клиентам..."/></label></div></div><table className="customers-table"><thead><tr><th>Клиент</th><th>Тип клиента</th><th>Контакты</th><th>Город / Регион</th><th>Статус</th><th>Действия</th></tr></thead><tbody>{visible.length?visible.map((r,i)=><tr key={r.id}><td><div className="client-name"><span className={`client-avatar c${i}`}>{(r.name||'?')[0]}</span><p><b>{r.name}</b><small>{r.notes||r.type}</small></p></div></td><td><span className={`client-type ${r.type==='wholesaler'?'wholesale':'retail'}`}>{r.type||'—'}</span></td><td>{r.phone||'—'}<br/><span>{r.email||'—'}</span></td><td>{r.address||'—'}</td><td><span className="client-status active">Активный</span></td><td className="field-actions-cell"><button className="icon-action" onClick={()=>setMenu(menu===r.id?null:r.id)}><FiMoreHorizontal/></button>{menu===r.id&&<div className="row-menu"><button onClick={async ()=>{const name=prompt('Имя клиента', r.name); if(name!==null) await actions.updateCustomer(r.id,{name}); setMenu(null);}}>Изменить</button><button className="danger" onClick={async ()=>{if(confirm('Удалить клиента?')) await actions.deleteCustomer(r.id); setMenu(null);}}>Удалить</button></div>}</td></tr>):<tr><td colSpan="6">Нет клиентов</td></tr>}</tbody></table><div className="field-footer"><span>Показано {visible.length} из {rows.length} клиентов</span><div><button><FiChevronLeft/></button><button className="current">1</button><button><FiChevronRight/></button></div></div></section></div>}
function SalesStats({rows=[]}){const revenue=rows.reduce((s,r)=>s+num(r.revenue_amount),0); const sold=rows.reduce((s,r)=>s+num(r.quantity_kg),0); const stats=[[FaChartLine,'Продаж',String(rows.length),'всего записей'],[FaRubleSign,'Выручка',`${revenue.toLocaleString('ru-RU')} ₽`,'по базе'],[FaBoxesStacked,'Продано продукции',formatKg(sold),'по базе'],[FaUsers,'Клиентов',String(new Set(rows.map(r=>r.customer_id)).size),'в продажах']];return <section className="sales-stats">{stats.map(([Icon,t,v,h])=><article className="sales-stat" key={t}><div><Icon/></div><p><span>{t}</span><b>{v}</b><small>{h}</small></p></article>)}</section>}
function PaymentIcon({state}){if(state==='paid')return <FiCheck/>; if(state==='wait')return <FiClock/>; return <FiMinusCircle/>}
function SalesPage({data,actions}){const rows=data.sales||[]; const customers=data.customers||[]; const inventory=data.inventory||[]; const [q,setQ]=useState(''); const [menu,setMenu]=useState(null); const visible=rows.filter(r=>`${r.customer_name||''} ${r.item_name||''}`.toLowerCase().includes(q.toLowerCase())); return <div className="sales-page"><div className="page-head"><div><h1>Продажи</h1><p>Учёт продаж продукции и работа с заказами</p></div><button className="add-field" onClick={actions.sale}><FiPlus/>Создать продажу</button></div><SalesStats rows={rows}/><section className="sales-card"><div className="fields-toolbar"><div className="tabs"><button className="active">Все продажи</button></div><div className="field-controls"><label><FiSearch/><input value={q} onChange={e=>setQ(e.target.value)} placeholder="Поиск по продажам..."/></label></div></div><table className="sales-table"><thead><tr><th>№ продажи</th><th>Дата</th><th>Клиент</th><th>Продукция</th><th>Количество</th><th>Сумма</th><th>Статус</th><th>Оплата</th><th>Действия</th></tr></thead><tbody>{visible.length?visible.map(r=><tr key={r.id}><td><b className="sale-id">S-{r.id}</b></td><td>{formatDate(r.sale_date)}</td><td>{r.customer_name||customers.find(c=>c.id===r.customer_id)?.name||`Клиент #${r.customer_id}`}</td><td><div className="sale-product"><span className={`crop-icon ${cropTypeFromName(r.item_name||'')}`}><CropIcon type={cropTypeFromName(r.item_name||'')}/></span><p><b>{r.item_name||inventory.find(i=>i.id===r.inventory_item_id)?.name||'—'}</b><small>{num(r.price_per_kg).toLocaleString('ru-RU')} ₽/кг</small></p></div></td><td>{formatKg(r.quantity_kg)}</td><td>{num(r.revenue_amount).toLocaleString('ru-RU')} ₽</td><td><span className={`sale-status ${r.status==='cancelled'?'cancel':'done'}`}>{r.status==='cancelled'?'Отменена':'Выполнена'}</span></td><td><span className={`payment ${r.status==='paid'?'paid':r.status==='cancelled'?'none':'wait'}`}><PaymentIcon state={r.status==='paid'?'paid':r.status==='cancelled'?'none':'wait'}/>{r.status==='paid'?'Оплачено':r.status==='cancelled'?'Отменено':'Ожидает оплату'}</span></td><td className="field-actions-cell"><button className="icon-action" onClick={()=>setMenu(menu===r.id?null:r.id)}><FiMoreHorizontal/></button>{menu===r.id&&<div className="row-menu"><button onClick={async ()=>{await actions.updateSale(r.id,{status:'paid'}); setMenu(null);}}>Оплачено</button><button onClick={async ()=>{await actions.updateSale(r.id,{status:'cancelled'}); setMenu(null);}}>Отменить</button><button className="danger" onClick={async ()=>{if(confirm('Удалить продажу?')) await actions.deleteSale(r.id); setMenu(null);}}>Удалить</button></div>}</td></tr>):<tr><td colSpan="9">Нет продаж</td></tr>}</tbody></table><div className="field-footer"><span>Показано {visible.length} из {rows.length} продаж</span><div><button><FiChevronLeft/></button><button className="current">1</button><button><FiChevronRight/></button></div></div></section></div>}
function AnalyticsPage({data, actions}) {
  const [range, setRange] = useState('month');
  const [view, setView] = useState('sum');
  const sales = data.sales || [];
  const tasks = data.tasks || [];
  const revenue = num(data.dashboard?.revenue, sales.length ? 248500 : 248500);
  const profit = num(data.dashboard?.profit, sales.length ? 86200 : 86200);
  const expenses = Math.max(revenue - profit, 162300);
  const soldKg = sales.reduce((sum, sale) => sum + num(sale.quantity_kg), 0) || 5900;
  const kpis = [
    [GiSprout, 'Выручка', `${revenue.toLocaleString('ru-RU')} ₽`, '+18% к прошлому месяцу', 'green'],
    [FaStore, 'Прибыль', `${profit.toLocaleString('ru-RU')} ₽`, '+21% к прошлому месяцу', 'green'],
    [FaChartLine, 'Расходы', `${expenses.toLocaleString('ru-RU')} ₽`, '+12% к прошлому месяцу', 'orange'],
    [FaBoxesStacked, 'Продано продукции', `${soldKg.toLocaleString('ru-RU')} кг`, '+16% к прошлому месяцу', 'blue'],
    [FaUsers, 'Новые клиенты', '7', '+3 к прошлому месяцу', 'violet']
  ];
  const crops = [
    ['Картофель', 40, 99400, 'green'], ['Томаты', 25, 62100, 'red'], ['Огурцы', 15, 37300, 'blue'], ['Пшеница', 10, 24800, 'sky'], ['Кукуруза', 5, 12900, 'orange'], ['Другие', 5, 11000, 'gray']
  ];
  const months = [['Дек 25',120],['Янв 26',135],['Фев 26',160],['Мар 26',190],['Апр 26',210],['Май 26',248]];
  const top = [['🥔','Картофель','42 600 ₽','+25%','up'],['🍅','Томаты','18 900 ₽','+18%','up'],['🥒','Огурцы','12 300 ₽','+12%','up'],['🌾','Пшеница','8 700 ₽','-5%','down'],['🌽','Кукуруза','3 800 ₽','+7%','up']];
  const taskStatus = [['Выполнено','14 (50%)','green'],['В процессе','8 (29%)','blue'],['Просрочено','4 (14%)','orange'],['Отменено','2 (7%)','gray']];
  return <div className="analytics-page">
    <div className="page-head analytics-head"><div><h1>Аналитика</h1><p>Ключевые показатели и аналитика по ферме</p></div><div className="head-actions"><button className="date-range" onClick={() => setRange(range === 'month' ? 'quarter' : 'month')}><FiCalendar />{range === 'month' ? 'Текущий месяц' : 'Текущий квартал'}<FiChevronDown /></button><button onClick={() => actions.exportXLSX('analytics')}><FiDownload />Экспорт XLSX</button></div></div>
    <section className="analytics-kpis">{kpis.map(([Icon,t,v,h,c])=><article className="analytics-kpi" key={t}><div className={c}><Icon/></div><p><span>{t}</span><b>{v}</b><small>{h}</small></p></article>)}</section>
    <section className="analytics-grid top">
      <article className="analytics-card line-card"><CardTitle title="Выручка и прибыль" action={range === 'month' ? 'По дням' : 'По неделям'} onClick={() => setRange(range === 'month' ? 'quarter' : 'month')} /><div className="chart-legend"><span><i className="green"></i>Выручка</span><span><i className="blue"></i>Прибыль</span></div><LineChart /></article>
      <article className="analytics-card revenue-card"><CardTitle title="Структура выручки по культурам" action={view === 'sum' ? 'По сумме' : 'По прибыли'} onClick={() => setView(view === 'sum' ? 'profit' : 'sum')} /><div className="revenue-layout"><div className="revenue-donut"><div><b>{revenue.toLocaleString('ru-RU')} ₽</b><span>Всего</span></div></div><ul className="revenue-list">{crops.map(c=><li key={c[0]}><i className={c[3]}></i><span>{c[0]}</span><b>{c[1]}%</b><strong>{(view === 'sum' ? c[2] : Math.round(c[2] * 0.35)).toLocaleString('ru-RU')} ₽</strong></li>)}</ul></div></article>
    </section>
    <section className="analytics-grid bottom">
      <article className="analytics-card"><CardTitle title="Продажи по месяцам" action={range === 'month' ? 'По месяцам' : 'По кварталу'} onClick={() => setRange(range === 'month' ? 'quarter' : 'month')} /><div className="bar-chart">{months.map(([m,v])=><div className="bar-col" key={m}><span>{v} тыс.</span><div style={{height:`${v}px`}}></div><small>{m}</small></div>)}</div></article>
      <article className="analytics-card"><h3>Топ культур по прибыли</h3><table className="profit-table"><thead><tr><th>Культура</th><th>Прибыль</th><th>Динамика</th></tr></thead><tbody>{top.map(r=><tr key={r[1]}><td><span>{r[0]}</span>{r[1]}</td><td>{r[2]}</td><td className={r[4]}>{r[3]} {r[4]==='up'?'↑':'↓'}</td></tr>)}</tbody></table></article>
      <article className="analytics-card task-card"><h3>Статус задач</h3><div className="task-layout"><div className="task-donut"><div><span>Всего</span><b>{tasks.length || 28}</b></div></div><ul className="task-status-list">{taskStatus.map(s=><li key={s[0]}><i className={s[2]}></i><span>{s[0]}</span><b>{s[1]}</b></li>)}</ul></div></article>
    </section>
    <p className="analytics-updated"><FiRefreshCw />Данные обновлены 31.05.2026 в 09:30</p>
  </div>
}
function CardTitle({title, action, onClick}) { return <div className="analytics-card-title"><h3>{title}</h3><button onClick={onClick}>{action}<FiChevronDown /></button></div> }
function LineChart(){const rev='M 30 190 L 115 115 L 205 105 L 305 95 L 405 70 L 500 60 L 590 40';const prof='M 30 215 L 115 202 L 205 190 L 305 170 L 405 172 L 500 160 L 590 190';return <svg className="line-chart" viewBox="0 0 640 260" role="img" aria-label="График выручки и прибыли"><g className="grid">{[40,80,120,160,200,240].map(y=><line key={y} x1="0" y1={y} x2="640" y2={y}/>)}</g><g className="axis"><text x="5" y="242">0</text><text x="5" y="202">50 тыс.</text><text x="5" y="162">100 тыс.</text><text x="5" y="122">150 тыс.</text><text x="5" y="82">200 тыс.</text><text x="5" y="42">250 тыс.</text><text x="40" y="258">1 мая</text><text x="210" y="258">8 мая</text><text x="360" y="258">15 мая</text><text x="505" y="258">22 мая</text><text x="590" y="258">31 мая</text></g><path className="line revenue" d={rev}/><path className="line profit" d={prof}/>{[[30,190],[115,115],[205,105],[305,95],[405,70],[500,60],[590,40]].map((p,i)=><circle className="point green" key={i} cx={p[0]} cy={p[1]} r="5"/>)}{[[30,215],[115,202],[205,190],[305,170],[405,172],[500,160],[590,190]].map((p,i)=><circle className="point blue" key={i} cx={p[0]} cy={p[1]} r="5"/>)} </svg>}
function ActionModal({kind,data,onClose,onSubmit}){const fields=data.fields||[],crops=data.crops||[],plantings=data.plantings||[],inventory=data.inventory||[],customers=data.customers||[];const presets={field:{title:'Добавить поле',sub:'Заполните информацию о новом поле',submit:'Создать поле',values:{name:'Поле №4',areaHectares:'2.5',location:'Грозненский район',soilType:'Чернозём',status:'ready'}},planting:{title:'Создать посев',sub:'Укажите поле, культуру и расход семян',submit:'Создать посев',values:{fieldID:fields[0]?.id||'',cropID:crops[0]?.id||'',seedQuantityKg:'500',expectedYieldKg:'6000'}},inventory:{title:'Добавить товар / семена',sub:'Пополните склад семян, удобрений или продукции',submit:'Добавить на склад',values:{type:'seed',name:'Семена картофеля',cropID:crops[0]?.id||'',quantityKg:'100',minQuantityKg:'300',averageCostPerKg:'18',unit:'кг'}},task:{title:'Создать задачу',sub:'Назначьте работу по полю или посеву',submit:'Создать задачу',values:{title:'Полив картофеля',description:'Проверить влажность и выполнить полив',type:'watering',dueDate:'2026-06-20',fieldID:fields[0]?.id||'',plantingID:plantings[0]?.id||''}},harvest:{title:'Добавить урожай',sub:'Зафиксируйте сбор и пополнение склада',submit:'Добавить урожай',values:{plantingID:plantings[0]?.id||'',cropID:crops[0]?.id||'',quantityKg:'5800',qualityGrade:'Отличное'}},customer:{title:'Добавить клиента',sub:'Сохраните покупателя или партнёра',submit:'Добавить клиента',values:{name:'Кафе Беркат',type:'restaurant',phone:'+7 900 000 00 00',email:'buyer@example.com',address:'Грозный',notes:'Интересуется картофелем'}},sale:{title:'Создать продажу',sub:'Система проверит остаток и спишет товар со склада',submit:'Создать продажу',values:{customerID:customers[0]?.id||'',inventoryItemID:inventory.find(i=>i.type==='harvest')?.id||'',quantityKg:'1000',pricePerKg:'35'}}};const cfg=presets[kind];const [form,setForm]=useState(cfg.values);const set=(k,v)=>setForm(p=>({...p,[k]:v}));const input=(k,l,t='text')=><label><span>{l}</span><input type={t} value={form[k]||''} onChange={e=>set(k,e.target.value)}/></label>;const select=(k,l,opts)=><label><span>{l}</span><select value={form[k]||''} onChange={e=>set(k,e.target.value)}>{opts.map(o=><option key={o[0]} value={o[0]}>{o[1]}</option>)}</select></label>;return <div className="modal-backdrop" role="dialog" aria-modal="true"><form className="action-modal" onSubmit={e=>{e.preventDefault();onSubmit(kind,form)}}><button type="button" className="modal-close" onClick={onClose}><FiChevronDown/></button><h2>{cfg.title}</h2><p>{cfg.sub}</p><div className="modal-grid">{kind==='field'&&<>{input('name','Название поля *')}{input('areaHectares','Площадь, га *','number')}{input('location','Местоположение *')}{select('status','Статус *',[['ready','Готово к посеву'],['planted','Занято посевом'],['resting','Отдыхает']])}{input('soilType','Тип почвы')}</>}{kind==='planting'&&<>{select('fieldID','Поле *',fields.map(f=>[f.id,f.name]))}{select('cropID','Культура *',crops.map(c=>[c.id,c.name]))}{input('seedQuantityKg','Семена, кг *','number')}{input('expectedYieldKg','Ожидаемый урожай, кг','number')}</>}{kind==='inventory'&&<>{select('type','Категория *',[['seed','Семена'],['harvest','Продукция'],['fertilizer','Удобрения'],['other','Прочее']])}{input('name','Название *')}{select('cropID','Культура',[[0,'Без культуры'],...crops.map(c=>[c.id,c.name])])}{input('quantityKg','Количество *','number')}{input('minQuantityKg','Мин. остаток','number')}{input('averageCostPerKg','Цена за кг','number')}</>}{kind==='task'&&<>{input('title','Название задачи *')}{select('type','Тип',[['watering','Полив'],['planting','Посадка'],['treatment','Обработка'],['purchase','Закупка'],['harvesting','Уборка']])}{input('dueDate','Срок','date')}{select('fieldID','Поле',[[0,'Без поля'],...fields.map(f=>[f.id,f.name])])}<label className="wide"><span>Описание</span><textarea value={form.description||''} onChange={e=>set('description',e.target.value)}/></label></>}{kind==='harvest'&&<>{select('plantingID','Посев',[[0,'Без посева'],...plantings.map(p=>[p.id,`${p.crop_name||'Посев'} · ${p.field_name||''}`])])}{select('cropID','Культура *',crops.map(c=>[c.id,c.name]))}{input('quantityKg','Количество, кг *','number')}{input('qualityGrade','Качество')}</>}{kind==='customer'&&<>{input('name','Клиент *')}{select('type','Тип',[['restaurant','Ресторан'],['shop','Магазин'],['wholesaler','Оптовый'],['person','Частное лицо']])}{input('phone','Телефон')}{input('email','Email')}{input('address','Город / адрес')}<label className="wide"><span>Заметки</span><textarea value={form.notes||''} onChange={e=>set('notes',e.target.value)}/></label></>}{kind==='sale'&&<>{select('customerID','Клиент *',customers.map(c=>[c.id,c.name]))}{select('inventoryItemID','Товар *',inventory.filter(i=>i.type==='harvest').map(i=>[i.id,`${i.name} · ${i.quantity_kg} кг`]))}{input('quantityKg','Количество, кг *','number')}{input('pricePerKg','Цена за кг *','number')}</>}</div><div className="modal-actions"><button type="button" onClick={onClose}>Отмена</button><button className="save-settings">{cfg.submit}</button></div></form></div>}
function SettingsPage({data, actions}){const sections=[['profile',FiUser,'Профиль','Личные данные'],['farm',FiHome,'Хозяйство','Информация о ферме'],['apiKeys',MdOutlineApi,'API-ключи','Интеграции и доступ'],['system',FiSettings,'Система','Импорт и экспорт']]; const [section,setSection]=useState('profile'); const me=data.me||{}; const farm=data.farm||{}; const [profile,setProfile]=useState({name:me.name||'', email:me.email||'', phone:me.phone||''}); const [farmForm,setFarmForm]=useState({name:farm.name||'', region:farm.region||'', address:farm.address||''}); useEffect(()=>{setProfile({name:me.name||'', email:me.email||'', phone:me.phone||''});},[me.name,me.email,me.phone]); useEffect(()=>{setFarmForm({name:farm.name||'', region:farm.region||'', address:farm.address||''});},[farm.name,farm.region,farm.address]); const apiKeys=data.apiKeys||[]; return <div className="settings-page"><div className="page-head settings-head"><div><h1>Настройки</h1><p>Управление профилем, хозяйством и системой</p></div></div><section className="settings-shell"><aside className="settings-nav" aria-label="Разделы настроек">{sections.map(([id,Icon,title,hint])=><button key={id} className={section===id?'active':''} onClick={()=>setSection(id)}><Icon/><p><b>{title}</b><span>{hint}</span></p></button>)}</aside><main className="settings-content">{section==='profile'&&<><div className="settings-title"><div><h2>Профиль</h2><p>Обновите личные данные владельца.</p></div><button className="save-settings" onClick={()=>actions.saveProfile(profile)}>Сохранить изменения</button></div><section className="settings-card profile-settings"><h3>Личные данные</h3><div className="settings-form-grid"><EditableField label="Имя" value={profile.name} onChange={v=>setProfile(p=>({...p,name:v}))}/><EditableField label="Email" value={profile.email} onChange={v=>setProfile(p=>({...p,email:v}))}/><EditableField label="Телефон" value={profile.phone} onChange={v=>setProfile(p=>({...p,phone:v}))}/><FormField label="Должность" value={me.role === 'owner' ? 'Владелец фермы' : (me.role || 'Пользователь')}/></div><div className="photo-block"><div className="photo-avatar"><FaRegUser/></div><button onClick={()=>alert('Загрузка фото будет добавлена позже')}><FiUpload/>Изменить фото</button><small>Профиль сохраняется в backend</small></div></section></>}{section==='farm'&&<><div className="settings-title"><div><h2>Хозяйство</h2><p>Обновите информацию о ферме.</p></div><button className="save-settings" onClick={()=>actions.saveFarm(farmForm)}>Сохранить изменения</button></div><section className="settings-card"><h3>Данные фермы</h3><div className="settings-form-grid"><EditableField label="Название" value={farmForm.name} onChange={v=>setFarmForm(p=>({...p,name:v}))}/><EditableField label="Регион" value={farmForm.region} onChange={v=>setFarmForm(p=>({...p,region:v}))}/><EditableField label="Адрес" value={farmForm.address} onChange={v=>setFarmForm(p=>({...p,address:v}))}/></div></section></>}{section==='apiKeys'&&<><div className="settings-title"><div><h2>API-ключи</h2><p>Создавайте и отзывайте ключи для внешних интеграций.</p></div><button className="save-settings" onClick={async ()=>{const name=prompt('Название ключа', 'Интеграция'); if(name) await actions.createApiKey(name);}}>Создать ключ</button></div><section className="settings-card"><h3>Список ключей</h3><div className="raw-grid">{apiKeys.length?apiKeys.map(k=><div key={k.id} className="settings-card"><b>{k.name}</b><p>{k.prefix}</p><small>{k.status}</small><div className="modal-actions"><button onClick={()=>actions.revokeApiKey(k.id)}>Отозвать</button></div></div>):<p>Ключей пока нет</p>}</div></section></>}{section==='system'&&<><div className="settings-title"><div><h2>Система</h2><p>Импортируйте и экспортируйте данные.</p></div></div><section className="settings-card"><h3>Импорт и экспорт</h3><div className="quick"><button onClick={()=>actions.importData('fields')}><FiUpload/>Импорт полей</button><button onClick={()=>actions.importData('inventory')}><FiUpload/>Импорт склада</button><button onClick={()=>actions.importData('customers')}><FiUpload/>Импорт клиентов</button><button onClick={()=>actions.exportXLSX('sales')}><FiDownload/>Экспорт продаж XLSX</button><button onClick={()=>actions.exportXLSX('inventory')}><FiDownload/>Экспорт склада XLSX</button><button onClick={()=>actions.exportXLSX('plantings')}><FiDownload/>Экспорт посевов XLSX</button></div></section></>}</main></section></div>}
function PublicApiPage({data, actions}) { const products = data.products || []; const sampleProduct = products[0]; const orderExample = {customerName:'Кафе Беркат', phone:'+7 900 000 00 00', email:'buyer@example.com', items: sampleProduct ? [{productId: sampleProduct.id, quantityKg: 300}] : [{productId: 1, quantityKg: 300}]}; const leadExample = {name:'Магазин Фреш', phone:'+7 928 000 00 00', email:'lead@example.com', message:'Интересует оптовая поставка картофеля'}; const endpoints = [{method:'GET', path:'/public/products', title:'Список доступной продукции', description:'Публичная витрина доступных товаров с остатками и ценой за кг.', sample: products.slice(0,2)}, {method:'POST', path:'/public/orders', title:'Создать внешний заказ', description:'Создаёт внешний заказ клиента по доступной продукции.', sample: orderExample}, {method:'POST', path:'/public/leads', title:'Создать лид', description:'Форма заявки для потенциальных покупателей и партнёров.', sample: leadExample}]; return <div className="api-page"><div className="page-head"><div><h1>Публичный API</h1><p>Открытые точки интеграции для витрины продукции, заказов и лидов</p></div><div className="head-actions"><button onClick={() => actions.exportRows('public-products.csv', [['ID','Название','Остаток кг','Цена за кг','Ферма'], ...products.map(p => [p.id, p.name, p.available_kg, p.price_per_kg, p.farm_name])])}><FiDownload />Экспорт списка</button><button className="add-field" onClick={actions.order}><FiPlus />Тестовый внешний заказ</button></div></div><section className="api-summary"><article><b>{products.length}</b><span>Товаров в публичной витрине</span></article><article><b>3</b><span>Открытых endpoint'а</span></article><article><b>JSON</b><span>Формат запросов и ответов</span></article></section><section className="api-grid">{endpoints.map(endpoint => <article key={endpoint.path} className="api-card"><div className="api-card-head"><span className={`api-method ${endpoint.method}`}>{endpoint.method}</span><code>{endpoint.path}</code></div><h3>{endpoint.title}</h3><p>{endpoint.description}</p><pre>{JSON.stringify(endpoint.sample, null, 2)}</pre>{endpoint.path === '/public/orders' && <button className="primary" onClick={actions.order}>Отправить тестовый заказ</button>}</article>)}</section><section className="api-products"><div className="section-title"><h2>Живая витрина продукции</h2></div><div className="raw-grid">{products.length ? products.map(product => <pre key={product.id}>{JSON.stringify(product, null, 2)}</pre>) : <p>Публичных товаров пока нет</p>}</div></section></div> }
function FormField({label,value}){return <label className="form-field"><span>{label}</span><input value={value} readOnly/></label>}
function EditableField({label,value,onChange}){return <label className="form-field"><span>{label}</span><input value={value} onChange={e=>onChange(e.target.value)} /></label>}
function PasswordField({label,hint,wide}) {return <label className={`form-field password-field ${wide?'wide':''}`}><span>{label}</span><div><input value="••••••••••••" readOnly/><FiEye/></div>{hint&&<small>{hint}</small>}</label>}
function SelectField({label,value}){return <label className="form-field select-field"><span>{label}</span><div><input value={value} readOnly/><FiChevronDown/></div></label>}
function SecondaryPage({tab, data, actions}) { if (tab === 'fields') return <FieldsPage data={data} actions={actions} />; if (tab === 'plantings') return <PlantingsPage data={data} actions={actions} />; if (tab === 'inventory') return <InventoryPage data={data} actions={actions} />; if (tab === 'harvests') return <HarvestPage data={data} actions={actions} />; if (tab === 'tasks') return <TasksPage data={data} actions={actions} />; if (tab === 'customers') return <CustomersPage data={data} actions={actions} />; if (tab === 'sales') return <SalesPage data={data} actions={actions} />; if (tab === 'analytics') return <AnalyticsPage data={data} actions={actions} />; if (tab === 'settings') return <SettingsPage data={data} actions={actions} />; if (tab === 'api') return <PublicApiPage data={data} actions={actions} />; const map = {}; const [title, items = []] = map[tab] || ['Раздел в разработке', []]; return <section className="panel full"><h2>{title}</h2><div className="raw-grid">{items.map(x => <pre key={x.id}>{JSON.stringify(x, null, 2)}</pre>)}</div></section> }

createRoot(document.getElementById('root')).render(<App />);
